const leads = $('HXN8N-GetWeeklyNewLeads').first().json;
const atRisk = $('HXN8N-GetAtRiskMembers').first().json;
const newLeadCount = leads.contacts ? leads.contacts.length : 0;
const atRiskCount = atRisk.contacts ? atRisk.contacts.length : 0;
const weekOf = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'America/Chicago' });
// Shell scoring — full targets loaded after onboarding
const targetNewLeads = parseInt('{{target_new_leads_per_week}}') || 5;
const targetAtRiskMax = parseInt('{{target_at_risk_threshold}}') || 8;
let kpisBelowTarget = 0;
if (newLeadCount < targetNewLeads) kpisBelowTarget++;
if (atRiskCount > targetAtRiskMax) kpisBelowTarget++;
let status = 'GREEN';
if (kpisBelowTarget === 1) status = 'YELLOW';
if (kpisBelowTarget >= 2) status = 'RED';
return [{ json: { weekOf, location: '{{location_name}}', newLeadCount, atRiskCount, targetNewLeads, targetAtRiskMax, kpisBelowTarget, status } }];

